const { ApolloServer, gql } = require('apollo-server');
const { GraphQLSchema } = require('graphql');
const { User } = require('./models/User');
const { Post } = require('./models/Post');
const { Comment } = require('./models/Comment');

// Define the schema
const typeDefs = gql`
  type Query {
    posts: [Post]
    comments: [Comment]
    users: [User]
  }

  type Post {
    id: ID!
    title: String!
    content: String!
    user: User!
    comments: [Comment]
  }

  type Comment {
    id: ID!
    content: String!
    post: Post!
    user: User!
  }

  type User {
    id: ID!
    name: String!
    email: String!
    posts: [Post]
    comments: [Comment]
  }
`;

// Define the resolvers
const resolvers = {
  Query: {
    posts: () => Post.find(),
    comments: () => Comment.find(),
    users: () => User.find()
  },
  Post: {
    user: (post) => User.findById(post.user),
    comments: (post) => Comment.find({ post: post._id })
  },
  Comment: {
    post: (comment) => Post.findById(comment.post),
    user: (comment) => User.findById(comment.user)
  },
  User: {
    posts: (user) => Post.find({ user: user._id }),
    comments: (user) => Comment.find({ user: user._id })
  }
};

// Create the Apollo Server
const server = new ApolloServer({
  typeDefs,
  resolvers,
  context: ({ req }) => {
    // Get the user from the request
    const user = req.user;

    // Return the user in the context
    return { user };
  }
});

// Start the server
server.listen().then(({ url }) => {
  console.log(`Server ready at ${url}`);
});